import yargs from "yargs";
import { hideBin } from "yargs/helpers";
import { promptApplicationRid } from "./prompts/promptApplicationRid.js";
import { promptApplicationUrl } from "./prompts/promptApplicationUrl.js";
import { promptClientId } from "./prompts/promptClientId.js";
import { promptCorsProxy } from "./prompts/promptCorsProxy.js";
import { promptFoundryUrl } from "./prompts/promptFoundryUrl.js";
import { promptOsdkPackage } from "./prompts/promptOsdkPackage.js";
import { promptOsdkRegistryUrl } from "./prompts/promptOsdkRegistryUrl.js";
import { promptOverwrite } from "./prompts/promptOverwrite.js";
import { promptProject } from "./prompts/promptProject.js";
import { promptScopes } from "./prompts/promptScopes.js";
import { promptSdkVersion } from "./prompts/promptSdkVersion.js";
import { promptTemplate } from "./prompts/promptTemplate.js";
import { run } from "./run.js";
export async function cli(args = process.argv) {
  const base = yargs(hideBin(args)).version(process.env.PACKAGE_VERSION ?? "").wrap(Math.min(150, yargs().terminalWidth())).strict().help().command("$0 [project] [--<option>]", "Create a new OSDK application based on framework templates. Information may be provided through options to skip interactive prompts.", yargs => yargs.positional("project", {
    type: "string",
    describe: "Project name to create"
  }).option("overwrite", {
    type: "boolean",
    describe: "Overwrite project directory if already exists"
  }).option("beta", {
    type: "boolean",
    describe: "Use templates compatible with the Beta version of the SDK"
  }).option("template", {
    type: "string",
    describe: "Template name to use"
  }).option("sdkVersion", {
    type: "string",
    describe: "The OSDK version to use"
  }).option("foundryUrl", {
    type: "string",
    describe: "URL for the Foundry stack"
  }).option("applicationUrl", {
    type: "string",
    describe: "URL the production application will be hosted on",
    conflicts: "skipApplicationUrl"
  }).option("skipApplicationUrl", {
    type: "boolean",
    describe: "Skip filling in URL the production application will be hosted on"
  }).option("application", {
    type: "string",
    describe: "Application resource identifier (rid)"
  }).option("clientId", {
    type: "string",
    describe: "OAuth client ID for application"
  }).option("osdkPackage", {
    type: "string",
    describe: "OSDK package name for application"
  }).option("osdkRegistryUrl", {
    type: "string",
    describe: "URL for NPM registry to install OSDK package"
  }).option("corsProxy", {
    type: "boolean",
    describe: "Include a CORS proxy for Foundry API requests during local development"
  }).option("scopes", {
    type: "string",
    array: true,
    describe: "List of client-side scopes to be used when creating a client"
  }));
  const parsed = base.parseSync();
  const project = await promptProject(parsed);
  const overwrite = await promptOverwrite({
    ...parsed,
    project
  });
  const template = await promptTemplate(parsed);
  const sdkVersion = await promptSdkVersion({
    ...parsed,
    template
  });
  const foundryUrl = await promptFoundryUrl(parsed);
  const applicationUrl = await promptApplicationUrl(parsed);
  const application = await promptApplicationRid(parsed);
  const clientId = await promptClientId(parsed);
  const osdkPackage = await promptOsdkPackage(parsed);
  const osdkRegistryUrl = await promptOsdkRegistryUrl(parsed);
  const corsProxy = await promptCorsProxy(parsed);
  const scopes = await promptScopes(parsed);
  await run({
    project,
    overwrite,
    template,
    sdkVersion,
    foundryUrl,
    applicationUrl,
    application,
    clientId,
    osdkPackage,
    osdkRegistryUrl,
    corsProxy,
    scopes
  });
}